"use strict";(globalThis.webpackChunkalvarolorente_dev=globalThis.webpackChunkalvarolorente_dev||[]).push([[9751],{1889(e,t,a){a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>i,default:()=>d,frontMatter:()=>r,metadata:()=>s,toc:()=>c});var s=a(8334),n=a(4848),o=a(8453);const r={title:"AI Didnt Kill ROI It Killed the Excuse",description:"Every time a CFO asks where the ROI from AI is, I think we are answering the wrong version of the question.",authors:"alvarolorentedev",tags:["substack"],draft:!1,series:"",canonical_url:"https://theengineeringtax.com/p/ai-didnt-kill-roi-it-killed-the-excuse",cover_image:"https://substack-post-media.s3.amazonaws.com/public/images/dea3e6e4-3a2e-46ab-9214-3261599d0ea0_1254x1254.png"},i=void 0,l={authorsImageUrls:[void 0]},c=[{value:"We Already Create More Than We Need",id:"we-already-create-more-than-we-need",level:2},{value:"Growth Is Not a Clean Product Signal",id:"growth-is-not-a-clean-product-signal",level:2},{value:"AI Makes the Old Problem Impossible to Ignore",id:"ai-makes-the-old-problem-impossible-to-ignore",level:2},{value:"Our Departments Are Already Oversized",id:"our-departments-are-already-oversized",level:2}];function h(e){const t={h2:"h2",img:"img",p:"p",...(0,o.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.p,{children:"Every time a CFO asks where the ROI from AI is, I think we are answering the wrong version of the question."}),"\n",(0,n.jsx)(t.p,{children:"The usual answer is that AI is not delivering enough value yet. That companies are spending money on tools, licenses, pilots, infrastructure, training, and consultants, but the financial return is not obvious. And honestly, that concern is fair. AI is becoming a real cost line. At some point, the story has to survive a spreadsheet."}),"\n",(0,n.jsx)(t.p,{children:"But I think the uncomfortable part is deeper."}),"\n",(0,n.jsx)(t.p,{children:"The problem is not only that AI ROI is hard to prove."}),"\n",(0,n.jsx)(t.p,{children:"The problem is that product ROI was already hard to prove."}),"\n",(0,n.jsx)(t.p,{children:"Most companies ship constantly. New features, integrations, dashboards, settings, onboarding changes, internal tools, compliance work, migrations, experiments, sales requests, customer-specific asks. Every week, the product changes. The roadmap moves. The release notes grow. The dashboards show activity. Then the business keeps growing, and we tell ourselves a convenient story: the product development machine created that growth."}),"\n",(0,n.jsx)(t.p,{children:"Sometimes it did."}),"\n",(0,n.jsx)(t.p,{children:"But often, I think we are much less sure than we pretend."}),"\n",(0,n.jsx)(t.p,{children:"A company can grow because the product is better. But it can also grow because the category is expanding, the sales team has strong relationships, customers have switching costs, procurement already approved the vendor, the brand feels safe, customer success protected renewals, pricing changed, a competitor stumbled, or the company has simply accumulated enough inertia that growth continues even when nobody can point to the exact product change that caused it."}),"\n",(0,n.jsx)(t.p,{children:"This does not mean product work has no value. It means the value signal is delayed, distributed, and messy."}),"\n",(0,n.jsx)(t.p,{children:"And AI is making that impossible to ignore."}),"\n",(0,n.jsx)(t.h2,{id:"we-already-create-more-than-we-need",children:"We Already Create More Than We Need"}),"\n",(0,n.jsx)(t.p,{children:"My suspicion is that many companies already create more product development work than they need."}),"\n",(0,n.jsx)(t.p,{children:"Not because people are lazy. Usually the opposite. People are working very hard. They are responding to customers, sales pressure, executive ideas, competitor comparisons, roadmap commitments, compliance requirements, internal escalations, platform needs, and the permanent pressure to show progress."}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.img,{src:"https://substack-post-media.s3.amazonaws.com/public/images/dea3e6e4-3a2e-46ab-9214-3261599d0ea0_1254x1254.png",alt:""})}),"\n",(0,n.jsx)(t.p,{children:"But the system is biased toward creation."}),"\n",(0,n.jsx)(t.p,{children:"It is easier to add than to remove. Easier to build than to say no. Easier to ship the small request than to challenge whether it should exist. Easier to satisfy the stakeholder than to explain why their idea is not strategically important. Easier to show a roadmap full of activity than a roadmap full of hard decisions."}),"\n",(0,n.jsx)(t.p,{children:"Over time, the product becomes a museum of accumulated commitments."}),"\n",(0,n.jsx)(t.p,{children:"Some of those commitments create value. Some protect value. Some reduce friction. Some help sales. Some are necessary but invisible. But many exist because, at some point, they were plausible, urgent, political, requested, or cheap enough to build."}),"\n",(0,n.jsx)(t.p,{children:"This is why feature adoption benchmarks are so uncomfortable. Pendo\u2019s research found that only a small percentage of features drive most usage. The exact number will not map perfectly to every product, but the pattern is familiar to anyone who has spent enough time inside a mature product. A small part of the product carries most of the usage. A long tail exists because someone once asked for it, someone once sold it, someone once feared removing it, or someone once needed the roadmap to look alive."}),"\n",(0,n.jsx)(t.p,{children:"That was already true before AI."}),"\n",(0,n.jsx)(t.p,{children:"Now imagine making the feature factory faster."}),"\n",(0,n.jsx)(t.p,{children:"Without changing the decision system."}),"\n",(0,n.jsx)(t.h2,{id:"growth-is-not-a-clean-product-signal",children:"Growth Is Not a Clean Product Signal"}),"\n",(0,n.jsx)(t.p,{children:"This is the part I think CFOs and product organizations both get wrong in different ways."}),"\n",(0,n.jsx)(t.p,{children:"CFOs may look at growth and assume it is connected to product development output. Product and engineering teams may look at growth and assume the same thing, because it validates the work. The business grew, therefore the roadmap mattered. Revenue expanded, therefore the features were worth it. Customers renewed, therefore the product investments were right."}),"\n",(0,n.jsx)(t.p,{children:"But growth is not that clean."}),"\n",(0,n.jsx)(t.p,{children:"Especially in B2B, revenue is a delayed signal. Buyers do not move in a straight line from feature to purchase. They build consensus. They revisit problems. They compare vendors. They wait for budget. They negotiate risk. They seek internal validation. They may buy because the product improved, but they may also buy because the organization already trusts the vendor, the implementation team is strong, the champion has political capital, or the cost of switching is too high."}),"\n",(0,n.jsx)(t.p,{children:"The same is true for existing customers. Renewals and expansions often come from accumulated trust, customer success work, procurement inertia, switching costs, usage habits, implementation depth, and relationship capital. Product matters, but not always in the linear way our roadmaps imply."}),"\n",(0,n.jsx)(t.p,{children:"So when the business grows, the product development machine avoids scrutiny."}),"\n",(0,n.jsx)(t.p,{children:"We assume the machine is working because the company is moving."}),"\n",(0,n.jsx)(t.p,{children:"But maybe the company is moving because of inertia, not because every new output created value."}),"\n",(0,n.jsx)(t.p,{children:"That is the painful distinction."}),"\n",(0,n.jsx)(t.p,{children:"The company may be growing with the product, but not because of all the product work."}),"\n",(0,n.jsx)(t.p,{children:"Some work creates value. Some protects value. Some is invisible but necessary. Some is waste. Some is pure feature-factory exhaust."}),"\n",(0,n.jsx)(t.p,{children:"And because the company is still growing, nobody is forced to ask which is which."}),"\n",(0,n.jsx)(t.h2,{id:"ai-makes-the-old-problem-impossible-to-ignore",children:"AI Makes the Old Problem Impossible to Ignore"}),"\n",(0,n.jsx)(t.p,{children:"AI changes this because it removes one of the last constraints: the cost of producing things."}),"\n",(0,n.jsx)(t.p,{children:"Before AI, effort acted as a filter. A feature required engineering time. A document required attention. A prototype required someone to build it. A test suite required effort. A support article required writing. A sales asset required time. This did not make the system good at prioritization, but at least production was expensive enough to create some friction."}),"\n",(0,n.jsx)(t.p,{children:"AI weakens that friction."}),"\n",(0,n.jsx)(t.p,{children:"Now every weak idea can have a spec. Every spec can have a prototype. Every prototype can generate code. Every code change can generate tests. Every meeting can generate a summary. Every summary can generate follow-up tasks. Every customer request can generate a polished justification. Every internal opinion can become a strategy document."}),"\n",(0,n.jsx)(t.p,{children:"The company starts producing more because it can."}),"\n",(0,n.jsx)(t.p,{children:"And this is where AI ROI gets confusing."}),"\n",(0,n.jsx)(t.p,{children:"AI may reduce the local cost of production. It may help a person write faster, summarize faster, code faster, analyze faster, respond faster. There is evidence of productivity gains in bounded contexts. But local acceleration is not the same as system value."}),"\n",(0,n.jsx)(t.p,{children:"If AI helps engineering write more code, someone still has to review it. If it helps product generate more ideas, someone still has to kill most of them. If it helps support answer faster, someone still has to detect the product pattern underneath. If it helps leadership generate more analysis, someone still has to make a decision. If it helps every department create more artifacts, the organization still has to validate, prioritize, maintain, explain, sell, support, and own those artifacts."}),"\n",(0,n.jsx)(t.p,{children:"That is the trap."}),"\n",(0,n.jsx)(t.p,{children:"AI can make output cheaper while making the company heavier."}),"\n",(0,n.jsx)(t.p,{children:"Because cheap to create is not cheap to own."}),"\n",(0,n.jsx)(t.p,{children:"Every feature still has a carrying cost: documentation, QA, security, support, maintenance, cognitive load, sales enablement, customer confusion, product surface area, and strategic distraction. AI can reduce creation cost, but it does not remove ownership cost."}),"\n",(0,n.jsx)(t.p,{children:"This is where slop enters the company."}),"\n",(0,n.jsx)(t.p,{children:"Not only as ugly AI content. As unnecessary work that looks professional enough to survive. A polished product brief with no real trade-off. A roadmap analysis with no decision. A generated PR that creates review burden. A strategy document that sounds smart but changes nothing. A customer summary that is fluent but misses the actual pain."}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.img,{src:"https://substack-post-media.s3.amazonaws.com/public/images/8ff8167b-559e-4d24-9f27-9f8b9f941588_1254x1254.png",alt:""})}),"\n",(0,n.jsx)(t.p,{children:"AI did not create the old bias toward output."}),"\n",(0,n.jsx)(t.p,{children:"It made it faster, cheaper, and harder to excuse."}),"\n",(0,n.jsx)(t.h2,{id:"our-departments-are-already-oversized",children:"Our Departments Are Already Oversized"}),"\n",(0,n.jsx)(t.p,{children:"This is the uncomfortable conclusion."}),"\n",(0,n.jsx)(t.p,{children:"Many departments are already too big for the amount of value they can actually validate."}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.img,{src:"https://substack-post-media.s3.amazonaws.com/public/images/89e230f0-84bd-4f4d-8dfb-ce95a1147b49_1254x1254.png",alt:""})}),"\n",(0,n.jsx)(t.p,{children:"Not too big because people are lazy. Too big because they were designed for an older world where producing work was expensive. More people meant more features, more documents, more tickets, more campaigns, more analysis, more delivery."}),"\n",(0,n.jsx)(t.p,{children:"AI breaks that logic."}),"\n",(0,n.jsx)(t.p,{children:"If output becomes cheap, output is no longer the scarce thing."}),"\n",(0,n.jsx)(t.p,{children:"Validation is."}),"\n",(0,n.jsx)(t.p,{children:"The real question is not whether AI can help us generate more. Of course it can. That is the least interesting part."}),"\n",(0,n.jsx)(t.p,{children:"The real question is whether we can finally admit that we were already generating too much."}),"\n",(0,n.jsx)(t.p,{children:"AI makes the waste impossible to hide."}),"\n",(0,n.jsx)(t.p,{children:"The companies that win with AI will not be the ones that produce the most. They will be the ones that need less production because they validate value better."}),"\n",(0,n.jsx)(t.p,{children:"Smaller departments."}),"\n",(0,n.jsx)(t.p,{children:"Sharper decisions."}),"\n",(0,n.jsx)(t.p,{children:"Fewer features."}),"\n",(0,n.jsx)(t.p,{children:"Less theater."}),"\n",(0,n.jsx)(t.p,{children:"More value."}),"\n",(0,n.jsx)(t.p,{children:"That is the ROI."})]})}function d(e={}){const{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(h,{...e})}):h(e)}},8453(e,t,a){a.d(t,{R:()=>r,x:()=>i});var s=a(6540);const n={},o=s.createContext(n);function r(e){const t=s.useContext(o);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function i(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:r(e.components),s.createElement(o.Provider,{value:t},e.children)}},8334(e){e.exports=JSON.parse('{"permalink":"/blog/2026/06/15/ai-didnt-kill-roi-it-killed-the-excuse","editUrl":"https://github.com/alvarolorentedev/website/tree/main/blog/2026-06-15-ai-didnt-kill-roi-it-killed-the-excuse.md","source":"@site/blog/2026-06-15-ai-didnt-kill-roi-it-killed-the-excuse.md","title":"AI Didnt Kill ROI It Killed the Excuse","description":"Every time a CFO asks where the ROI from AI is, I think we are answering the wrong version of the question.","date":"2026-06-15T00:00:00.000Z","tags":[{"inline":true,"label":"substack","permalink":"/blog/tags/substack"}],"readingTime":7.4,"hasTruncateMarker":true,"authors":[{"name":"Alvaro Jose","title":"Fractional CTO & Founder","url":"https://github.com/alvarolorentedev","imageURL":"https://avatars.githubusercontent.com/u/3071208","key":"alvarolorentedev","page":null}],"frontMatter":{"title":"AI Didnt Kill ROI It Killed the Excuse","description":"Every time a CFO asks where the ROI from AI is, I think we are answering the wrong version of the question.","authors":"alvarolorentedev","tags":["substack"],"draft":false,"series":"","canonical_url":"https://theengineeringtax.com/p/ai-didnt-kill-roi-it-killed-the-excuse","cover_image":"https://substack-post-media.s3.amazonaws.com/public/images/dea3e6e4-3a2e-46ab-9214-3261599d0ea0_1254x1254.png"},"unlisted":false,"nextItem":{"title":"The Hardest Part of AI Is Letting Go of Our Ego","permalink":"/blog/2026/05/13/the-hardest-part-of-ai-is-letting-go-of-our-ego"}}')}}]);